const items = $input.all();

const chunkSize = 10;
const chunks = [];

for (let i = 0; i < items.length; i += chunkSize) {
  const chunk = items.slice(i, i + chunkSize);

  chunks.push({
    json: {
      chunk_id: Math.floor(i / chunkSize) + 1,
      total_ofertas: chunk.length,
      ofertas: chunk.map(item => item.json)
    }
  });
}

return chunks;

const ofertas = $json.ofertas || [];
const total = $json.total || ofertas.length;
const fecha = new Date().toLocaleDateString('es-AR');

function escapeHtml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

function renderList(arr) {
  if (!Array.isArray(arr) || arr.length === 0) {
    return '<li>No especificado.</li>';
  }

  return arr
    .map(x => `<li>${escapeHtml(x)}</li>`)
    .join('');
}

function scoreColor(score) {
  const n = Number(score || 0);

  if (n >= 90) return '#16a34a';
  if (n >= 80) return '#2563eb';
  if (n >= 70) return '#d97706';

  return '#6b7280';
}

let html = `
<div style="margin:0; padding:0; background:#f3f4f6; font-family:Arial, Helvetica, sans-serif; color:#111827;">
  <div style="max-width:920px; margin:0 auto; padding:28px 18px;">

    <div style="background:#111827; color:white; border-radius:18px; padding:26px; margin-bottom:22px;">
      <h1 style="margin:0 0 10px; font-size:28px;">
        Ofertas laborales compatibles
      </h1>
      <p style="margin:0; font-size:15px; color:#d1d5db;">
        Informe generado automáticamente a partir del CV y las ofertas cargadas.
      </p>
    </div>

    <div style="background:white; border:1px solid #e5e7eb; border-radius:16px; padding:20px; margin-bottom:22px;">
      <p style="margin:0 0 8px;">
        <strong>Fecha:</strong> ${escapeHtml(fecha)}
      </p>
      <p style="margin:0;">
        <strong>Total de ofertas compatibles:</strong> ${escapeHtml(total)}
      </p>
    </div>
`;

if (ofertas.length === 0) {
  html += `
    <div style="background:white; border:1px solid #e5e7eb; border-radius:16px; padding:22px;">
      <h2 style="margin-top:0;">No se encontraron ofertas compatibles</h2>
      <p style="margin-bottom:0;">
        No hubo ofertas con puntaje suficiente para recomendar postulación.
      </p>
    </div>
  `;
}

for (const o of ofertas) {
  const score = Number(o.score || o.puntaje || 0);
  const color = scoreColor(score);
  const url = o.url || o.enlace || o.link || '';

  html += `
    <div style="background:white; border:1px solid #e5e7eb; border-radius:18px; padding:22px; margin-bottom:20px; box-shadow:0 4px 14px rgba(0,0,0,0.05);">

      <div style="display:flex; justify-content:space-between; align-items:flex-start; gap:16px; flex-wrap:wrap;">
        <div>
          <h2 style="margin:0 0 8px; color:#111827; font-size:22px;">
            ${escapeHtml(o.puesto || 'Oferta compatible')}
          </h2>
          <p style="margin:0; color:#374151;">
            <strong>Empresa:</strong> ${escapeHtml(o.empresa || 'Sin empresa')}
          </p>
        </div>

        <div style="background:${color}; color:white; padding:10px 14px; border-radius:12px; font-weight:bold; font-size:18px;">
          ${escapeHtml(score)}/100
        </div>
      </div>

      <hr style="border:none; border-top:1px solid #e5e7eb; margin:18px 0;" />

      <p style="margin:8px 0;">
        <strong>Compatibilidad:</strong> ${escapeHtml(o.compatibilidad || 'No especificada')}
      </p>

      <p style="margin:8px 0;">
        <strong>Recomendación:</strong> ${escapeHtml(o.recomendacion || 'Revisar')}
      </p>

      <div style="margin-top:16px;">
        <p style="margin:0 0 6px;"><strong>Por qué encaja:</strong></p>
        <ul style="margin-top:6px; padding-left:22px;">
          ${renderList(o.motivos)}
        </ul>
      </div>

      <div style="margin-top:16px;">
        <p style="margin:0 0 6px;"><strong>Faltantes o puntos a revisar:</strong></p>
        <ul style="margin-top:6px; padding-left:22px;">
          ${renderList(o.faltantes)}
        </ul>
      </div>

      ${
        url
          ? `<div style="margin-top:18px;">
              <a href="${escapeHtml(url)}" target="_blank" style="display:inline-block; background:#2563eb; color:white; padding:10px 14px; border-radius:10px; text-decoration:none; font-weight:bold;">
                Ver oferta
              </a>
              <p style="font-size:12px; color:#6b7280; margin-top:8px; word-break:break-all;">
                ${escapeHtml(url)}
              </p>
            </div>`
          : `<p style="margin-top:18px; color:#6b7280;"><em>Sin enlace disponible.</em></p>`
      }

    </div>
  `;
}

html += `
    <div style="text-align:center; color:#6b7280; font-size:12px; margin-top:28px;">
      Informe generado por n8n + IA.
    </div>

  </div>
</div>
`;

return [
  {
    json: {
      html,
      total,
      ofertas
    }
  }
];

const items = $input.all();

let resultadosIA = [];

function cleanParse(value) {
  if (typeof value !== 'string') return value;

  const clean = value
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  return JSON.parse(clean);
}

for (const item of items) {
  let data = item.json;

  if (typeof data.output === 'string') {
    data = cleanParse(data.output);
  }

  const compatibles = data.ofertas_compatibles || data.top_ofertas || [];

  for (const r of compatibles) {
    resultadosIA.push({
      oferta_id: Number(r.oferta_id || 0),
      empresa: r.empresa || '',
      puesto: r.puesto || '',
      url: r.url || r.enlace || r.link || '',
      score: Number(r.score || r.puntaje || 0),
      compatibilidad: r.compatibilidad || '',
      motivos: Array.isArray(r.motivos) ? r.motivos : [],
      faltantes: Array.isArray(r.faltantes) ? r.faltantes : [],
      recomendacion: r.recomendacion || ''
    });
  }
}

resultadosIA = resultadosIA.sort((a, b) => b.score - a.score);

const ofertasMayoresA70 = resultadosIA.filter(r => r.score >= 70);

const ofertasFinales =
  ofertasMayoresA70.length > 0
    ? ofertasMayoresA70
    : resultadosIA.slice(0, 15);

return [
  {
    json: {
      total: ofertasFinales.length,
      ofertas: ofertasFinales
    }
  }
];

const items = $input.all();

return items.map((item, index) => {
  item.json.oferta_id = index + 1;
  return item;
});
